mapper.delete:
DELETE FROM 
    role_permission
WHERE 
    role_id = #{roleId}
AND 
    permission_id = #{permissionId}

mapper.update:
UPDATE 
    role_permission
SET 
    chg_id = #{chgId},
    chg_dt = COALESCE(#{chgDt}, NOW()),
    del_yn = #{delYn}
WHERE 
    role_id = #{roleId}
AND 
    permission_id = #{permissionId}

mapper.select:
SELECT EXISTS(
    SELECT 
        1 
    FROM 
        role_permission rolePermission

    WHERE 
        role_id = #{roleId}
    AND 
        permission_id = #{permissionId}
)

SELECT rp.role_id, rp.permission_id, r.role_name, p.permission_name, p.description, rp.reg_id, rp.reg_dt, rp.chg_id, rp.chg_dt, rp.del_id, rp.del_dt, rp.del_yn FROM role_permission rp INNER JOIN role r ON rp.role_id = r.role_id INNER JOIN permission p ON rp.permission_id = p.permission_id
AND rp.role_id IN
#{roleId}
AND rp.permission_id IN
#{permissionId}
AND r.role_name ILIKE '%' || #{filter.roleName} || '%'
AND p.permission_name ILIKE '%' || #{filter.permissionName} || '%'
AND rp.del_yn = #{filter.delYn}
ORDER BY rp.reg_dt DESC
